actor Counter {
    var count: i64;
    receive fn increment(by: i64) -> i64 {
        count = count + by;
        count
    }
}

fn main() {
    let c = spawn Counter(count: 0);
    await c.increment(5);
}

// `await` sends a message and waits for the reply (a Result).
match await counter.increment(5) {
    Ok(total) => println(total),
    Err(_) => {}
}

actor Greeter {
    let name: string;
    receive fn greet() -> i64 {
        println(f"Hello from {name}");
        0
    }
}

fn main() {
    let g = spawn Greeter(name: "Hew");
    await g.greet();
}

actor Worker {
    let id: i64;

    receive fn work(x: i64) -> i64 {
        println(f"Worker {id} processing {x}");
        x * 2
    }
}

supervisor WorkerPool {
    strategy: one_for_one;
    intensity: 5 within 60s;
    child w1: Worker(id: 1);
    child w2: Worker(id: 2);
}

fn main() {
    let workers = spawn WorkerPool;
    let w1 = workers.w1;
    await w1.work(10);
}

machine Light {
    events { Toggle; }
    state Off;
    state On;
    on Toggle: Off => On;
    on Toggle: On => Off;
}

fn main() -> i64 {
    var light = Light::Off;
    println(light.state_name());
    light.step(Toggle);
    println(light.state_name());
    light.step(Toggle);
    println(light.state_name());
    0
}

