// Hew has no `async fn` — actors are the unit of concurrency.
actor Fetcher {
    receive fn get(url: string) -> string {
        "response body"
    }
}

fn main() {
    let fetcher = spawn Fetcher;
    match await fetcher.get("https://example.com") {
        Ok(body) => println(body),
        Err(_) => println("request failed"),
    }
}

// `await` returns a Result with the actor's reply.
match await fetcher.get("https://example.com") {
    Ok(body) => println(body),
    Err(_) => println("request failed"),
}

